import { clearActiveStudioSession, readActiveStudioSession, } from "../activeStudioSession.js";
import { closeStudioWindowsBySession } from "../browser.js";
import { emitJson } from "../output.js";
import { positionalArgs } from "../parseArgs.js";
import { killPollerProcess, killStudioWindow } from "../studioTeardown.js";
/**
 * Explicit recovery for a stale Studio pointer. `openStudioTo` gates (emits
 * `not-responding`) when the recorded window is believed live but unreachable
 * (crash, sleep, or a close no process witnessed); it never replaces it
 * automatically. After the user approves recovery, run this to remove the
 * pointer, then re-run `openStudioTo.js` to open a fresh window.
 *
 * Clearing means the user is abandoning the recorded session, so reap its
 * processes too (both best-effort, session-matched): the `--app` window (if
 * it was alive-but-unreachable, it would otherwise linger as a zombie next to
 * the fresh one) and the event poller still attached to the dead session.
 *
 * With a `sessionId` arg, clears only that session's pointer; with none, clears
 * whatever is currently recorded for this scope. Always a deliberate (forced)
 * clear, but still matched on sessionId so a different session is never touched.
 */
export function runClearStudioSession() {
    const ARGS = [
        {
            name: "sessionId",
            required: false,
            format: "uuid",
            description: "Studio session whose pointer to clear. Defaults to whatever session is currently recorded.",
        },
    ];
    const args = positionalArgs(ARGS, process.argv, {
        description: "Clear a stale Studio window pointer so a fresh window can be opened. Run after openStudioTo reports not-responding and the user approves recovery. Emits one JSON line: cleared, not-found, or no-active-studio.",
    });
    const record = readActiveStudioSession();
    const sessionId = args[0] ?? record?.sessionId ?? null;
    if (!sessionId) {
        emitJson({ event: "no-active-studio" });
        return;
    }
    // Reap BEFORE clearing: the kills resolve their pids from the record, which
    // is gone afterwards. Both helpers re-check the sessionId, so they no-op if
    // the record was re-bound (and the clear below then reports not-found).
    killStudioWindow(sessionId);
    // The pid kill is a no-op when the browser was already running (dead launcher
    // pid), so also best-effort close the window by URL match — unless the record
    // already shows this session closed, in which case nothing is left to close.
    const alreadyClosed = record?.sessionId === sessionId && record.windowState === "closed";
    if (!alreadyClosed) {
        closeStudioWindowsBySession(sessionId);
    }
    killPollerProcess(sessionId);
    // Report what actually happened: `clearActiveStudioSession` no-ops when the
    // recorded pointer names a different session, so emitting `cleared`
    // unconditionally would falsely claim success while a stale pointer remains.
    const cleared = clearActiveStudioSession(sessionId, { force: true });
    emitJson({ event: cleared ? "cleared" : "not-found", sessionId });
}
